import { createClient } from '@supabase/supabase-js';
import { LexicalEntry, UserProfile } from '../types';

// Assume these environment variables are provided in the environment
const supabaseUrl = (process.env as any).SUPABASE_URL || '';
const supabaseAnonKey = (process.env as any).SUPABASE_ANON_KEY || '';

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

/**
 * Expected Schema:
 * 
 * table: lex_profiles
 * - user_id (text, primary key)
 * - profile_json (jsonb)
 * - updated_at (timestamp with time zone)
 * 
 * table: lex_history
 * - id (uuid, primary key)
 * - user_id (text)
 * - term (text)
 * - entry_json (jsonb)
 * - timestamp (bigint)
 */

export async function fetchProfile(userId: string): Promise<UserProfile | null> {
  if (!supabaseUrl) return null;
  const { data, error } = await supabase
    .from('lex_profiles')
    .select('profile_json')
    .eq('user_id', userId)
    .single();

  if (error || !data) return null;
  return data.profile_json as UserProfile;
}

export async function upsertProfile(userId: string, profile: UserProfile) {
  if (!supabaseUrl) return;
  await supabase
    .from('lex_profiles')
    .upsert({ 
      user_id: userId, 
      profile_json: profile, 
      updated_at: new Date().toISOString() 
    });
}

export async function fetchHistory(userId: string): Promise<LexicalEntry[]> {
  if (!supabaseUrl) return [];
  const { data, error } = await supabase
    .from('lex_history')
    .select('entry_json')
    .eq('user_id', userId)
    .order('timestamp', { ascending: false })
    .limit(50);

  if (error || !data) return [];
  return data.map(item => item.entry_json as LexicalEntry);
}

export async function saveHistoryEntry(userId: string, entry: LexicalEntry) {
  if (!supabaseUrl) return;
  await supabase
    .from('lex_history')
    .upsert({
      user_id: userId,
      term: entry.term,
      entry_json: entry,
      timestamp: entry.timestamp
    }, { onConflict: 'user_id, term' });
}

import React, { useState, useEffect, useCallback } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { fetchProfile, fetchHistory, upsertProfile, saveHistoryEntry } from './services/supabase';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'synced' | 'syncing' | 'offline'>('syncing');

  // Generate or retrieve a persistent Device ID for the database session
  const [deviceId] = useState(() => {
    let id = localStorage.getItem('lexDeviceId');
    if (!id) {
      id = crypto.randomUUID();
      localStorage.setItem('lexDeviceId', id);
    }
    return id;
  });

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    return saved ? JSON.parse(saved) : {
      username: 'Scholar',
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  // INITIAL HYDRATION: Fetch from Supabase
  useEffect(() => {
    const hydrate = async () => {
      setSyncStatus('syncing');
      try {
        const [cloudProfile, cloudHistory] = await Promise.all([
          fetchProfile(deviceId),
          fetchHistory(deviceId)
        ]);

        if (cloudProfile) setProfile(cloudProfile);
        if (cloudHistory && cloudHistory.length > 0) setHistory(cloudHistory);

        setSyncStatus('synced');
      } catch (err) {
        console.error("Supabase Hydration Error:", err);
        setSyncStatus('offline');
      } finally {
        setIsLoading(false);
      }
    };

    hydrate();

    // Telegram setup
    if ((window as any).Telegram?.WebApp) {
      const tg = (window as any).Telegram.WebApp;
      tg.ready();
      tg.expand();
      if (tg.initDataUnsafe?.user?.username) {
        setProfile(p => ({ ...p, username: tg.initDataUnsafe.user.username }));
      }
    }
  }, [deviceId]);

  // LOCAL STORAGE FALLBACKS & SYNC HELPERS
  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    localStorage.setItem('lexProfile', JSON.stringify(profile));
  }, [profile]);

  useEffect(() => {
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [autoAudio]);

  const syncProfile = useCallback(async (newProfile: UserProfile) => {
    setSyncStatus('syncing');
    try {
      await upsertProfile(deviceId, newProfile);
      setSyncStatus('synced');
    } catch {
      setSyncStatus('offline');
    }
  }, [deviceId]);

  const addEntry = async (entry: LexicalEntry) => {
    const newHistory = [entry, ...history.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase())].slice(0, 50);
    setHistory(newHistory);

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);

    // Background cloud sync
    try {
      await Promise.all([
        saveHistoryEntry(deviceId, entry),
        syncProfile(newProfile)
      ]);
    } catch (e) {
      console.warn("Cloud sync failed, data saved locally.");
    }
  };

  const handleArenaResult = async (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = (correctCount / totalQuestions) * 100;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = profile.accuracy === 100 ? sessionAccuracy : (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
    syncProfile(newProfile);
  };

  const handleHistoryItemClick = (entry: LexicalEntry) => {
    setActiveEntry(entry);
    setMode(AppMode.DICTIONARY);
  };

  const navigateToDictionary = () => {
    setMode(AppMode.DICTIONARY);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-[#fcfcfb] flex flex-col items-center justify-center">
        <div className="text-6xl serif font-black tracking-tighter text-[#7c1a1a] animate-pulse mb-4">LEX.</div>
        <div className="text-[10px] uppercase tracking-[0.5em] text-stone-400 font-bold animate-bounce">Consulting Archives...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-6 md:px-12 py-10 max-w-[1400px] mx-auto w-full flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="flex items-center gap-6">
          <span 
            onClick={navigateToDictionary}
            className="text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a] hover:scale-105 transition-transform"
          >
            LEX.
          </span>
          <div className="h-8 w-[1px] bg-stone-200"></div>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase tracking-[0.5em] text-stone-900 font-black leading-none mb-1">
              The Polyglot Insight Engine
            </span>
            <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival philology & context
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-10 text-[10px] uppercase tracking-[0.3em] font-black text-stone-400">
          <button 
            onClick={navigateToDictionary} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => setMode(AppMode.ARENA)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            The Arena
          </button>
          <button 
            onClick={() => setMode(AppMode.ARCHIVE)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Chronicles
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => setMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={handleHistoryItemClick}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} onEntryClick={handleHistoryItemClick} />
          )}
        </div>
      </main>

      <footer className="py-12 border-t border-stone-100 bg-white/50">
        <div className="max-w-[1400px] mx-auto px-12 flex flex-col md:flex-row justify-between items-center gap-6 text-[10px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex items-center gap-4">
             <span>&copy; 2025 LEXICON PHILOLOGY</span>
             <span className="text-stone-200">/</span>
             <span className={`flex items-center gap-1.5 ${syncStatus === 'synced' ? 'text-green-600' : syncStatus === 'syncing' ? 'text-amber-500' : 'text-red-500'}`}>
                <span className={`w-1.5 h-1.5 rounded-full ${syncStatus === 'synced' ? 'bg-green-500' : syncStatus === 'syncing' ? 'bg-amber-500 animate-pulse' : 'bg-red-500'}`}></span>
                {syncStatus.toUpperCase()} CLOUD
             </span>
          </div>
          <div className="flex items-center gap-8">
            <span className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-[#7c1a1a] animate-pulse"></span>
              {profile.rank}
            </span>
            <span className="text-stone-900">LVL {Math.floor(profile.xp / 1000) + 1}</span>
            <span className="text-stone-300">{profile.accuracy}% ACCURACY</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

