  if (!userId) return;
  await supabase
    .from('lex_history')
    .upsert({
      user_id: userId,
      term: entry.term,
      entry_json: entry,
      timestamp: entry.timestamp
    }, { onConflict: 'user_id, term' });
}

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { AppMode, LexicalEntry, UserProfile } from './types';
import Dictionary from './components/Dictionary';
import Arena from './components/Arena';
import Archive from './components/Archive';
import { RANKS } from './constants';
import { fetchProfile, fetchHistory, upsertProfile, saveHistoryEntry } from './services/supabase';

const App: React.FC = () => {
  const [mode, setMode] = useState<AppMode>(AppMode.DICTIONARY);
  const [history, setHistory] = useState<LexicalEntry[]>([]);
  const [activeEntry, setActiveEntry] = useState<LexicalEntry | null>(null);
  const [autoAudio, setAutoAudio] = useState(() => localStorage.getItem('autoAudio') === 'true');
  const [isLoading, setIsLoading] = useState(true);
  const [syncStatus, setSyncStatus] = useState<'synced' | 'syncing' | 'offline'>('syncing');

  // Telegram WebApp Instance
  const tg = (window as any).Telegram?.WebApp;

  // Stable ID for cloud storage (Telegram ID is preferred for cross-device sync)
  const userId = useMemo(() => {
    if (tg?.initDataUnsafe?.user?.id) {
      return `tg-${tg.initDataUnsafe.user.id}`;
    }
    let id = localStorage.getItem('lexDeviceId');
    if (!id) {
      id = crypto.randomUUID();
      localStorage.setItem('lexDeviceId', id);
    }
    return id;
  }, [tg]);

  const [profile, setProfile] = useState<UserProfile>(() => {
    const saved = localStorage.getItem('lexProfile');
    const tgUser = tg?.initDataUnsafe?.user;
    const initialName = tgUser ? (tgUser.first_name + (tgUser.last_name ? ` ${tgUser.last_name}` : '')) : 'Scholar';

    return saved ? JSON.parse(saved) : {
      username: initialName,
      xp: 0,
      rank: RANKS[0].title,
      searchCount: 0,
      arenaWins: 0,
      accuracy: 100,
      streak: 0
    };
  });

  // Trigger Telegram Haptic Feedback
  const triggerHaptic = useCallback((type: 'light' | 'medium' | 'heavy' | 'success' | 'warning' | 'error' = 'light') => {
    if (tg?.HapticFeedback) {
      if (['success', 'warning', 'error'].includes(type)) {
        tg.HapticFeedback.notificationOccurred(type);
      } else {
        tg.HapticFeedback.impactOccurred(type);
      }
    }
  }, [tg]);

  // INITIAL HYDRATION & TELEGRAM SETUP
  useEffect(() => {
    if (tg) {
      tg.ready();
      tg.expand();
      tg.setHeaderColor('#fcfcfb');
      tg.setBackgroundColor('#fcfcfb');

      const tgUser = tg.initDataUnsafe?.user;
      const tgName = tgUser ? (tgUser.first_name + (tgUser.last_name ? ` ${tgUser.last_name}` : '')) : null;

      if (tgName && profile.username !== tgName) {
        setProfile(prev => ({ ...prev, username: tgName }));
      }
    }

    const hydrate = async () => {
      setSyncStatus('syncing');
      try {
        const [cloudProfile, cloudHistory] = await Promise.all([
          fetchProfile(userId),
          fetchHistory(userId)
        ]);

        if (cloudProfile) {
          const tgUser = tg?.initDataUnsafe?.user;
          const currentName = tgUser ? (tgUser.first_name + (tgUser.last_name ? ` ${tgUser.last_name}` : '')) : cloudProfile.username;
          setProfile({ ...cloudProfile, username: currentName });
        }
        if (cloudHistory && cloudHistory.length > 0) setHistory(cloudHistory);

        setSyncStatus('synced');
      } catch (err) {
        console.error("Supabase Hydration Error:", err);
        setSyncStatus('offline');
      } finally {
        setIsLoading(false);
      }
    };

    hydrate();
  }, [userId, tg]);

  // LOCAL STORAGE FALLBACKS
  useEffect(() => {
    localStorage.setItem('lexHistory', JSON.stringify(history));
    localStorage.setItem('lexProfile', JSON.stringify(profile));
    localStorage.setItem('autoAudio', String(autoAudio));
  }, [history, profile, autoAudio]);

  const syncProfile = useCallback(async (newProfile: UserProfile) => {
    setSyncStatus('syncing');
    try {
      await upsertProfile(userId, newProfile);
      setSyncStatus('synced');
    } catch {
      setSyncStatus('offline');
    }
  }, [userId]);

  const addEntry = async (entry: LexicalEntry) => {
    triggerHaptic('light');
    const newHistory = [entry, ...history.filter(p => p.term.toLowerCase() !== entry.term.toLowerCase())].slice(0, 50);
    setHistory(newHistory);

    const newXp = profile.xp + 2;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      searchCount: profile.searchCount + 1 
    };

    setProfile(newProfile);

    try {
      await Promise.all([
        saveHistoryEntry(userId, entry),
        syncProfile(newProfile)
      ]);
    } catch (e) {
      console.warn("Cloud sync failed.");
    }
  };

  const handleArenaResult = async (correctCount: number, totalQuestions: number) => {
    const earnedXp = correctCount * 5;
    const sessionAccuracy = (correctCount / totalQuestions) * 100;

    const newXp = profile.xp + earnedXp;
    const newRank = RANKS.reduce((prev, curr) => newXp >= curr.minXp ? curr : prev, RANKS[0]);
    const newAccuracy = profile.accuracy === 100 ? sessionAccuracy : (profile.accuracy + sessionAccuracy) / 2;

    const newProfile = { 
      ...profile, 
      xp: newXp, 
      rank: newRank.title,
      arenaWins: profile.arenaWins + 1,
      accuracy: Math.round(newAccuracy),
      streak: correctCount === totalQuestions ? profile.streak + 1 : 0
    };

    setProfile(newProfile);
    syncProfile(newProfile);
  };

  const changeMode = (newMode: AppMode) => {
    triggerHaptic('light');
    setMode(newMode);
    if (newMode === AppMode.DICTIONARY) setActiveEntry(null);
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-[#fcfcfb] flex flex-col items-center justify-center">
        <div className="text-6xl serif font-black tracking-tighter text-[#7c1a1a] animate-pulse mb-4">LEX.</div>
        <div className="text-[10px] uppercase tracking-[0.5em] text-stone-400 font-bold animate-bounce">Consulting Archives...</div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#fcfcfb] flex flex-col selection:bg-[#7c1a1a]/10 selection:text-[#7c1a1a]">
      <header className="px-6 md:px-12 py-10 max-w-[1400px] mx-auto w-full flex flex-col md:flex-row items-center justify-between gap-8">
        <div className="flex items-center gap-6">
          <span 
            onClick={() => changeMode(AppMode.DICTIONARY)}
            className="text-4xl serif font-black tracking-tighter cursor-pointer text-[#7c1a1a] hover:scale-105 transition-transform"
          >
            LEX.
          </span>
          <div className="h-8 w-[1px] bg-stone-200"></div>
          <div className="flex flex-col">
            <span className="text-[10px] uppercase tracking-[0.5em] text-stone-900 font-black leading-none mb-1">
              {profile.username}'s Engine
            </span>
            <span className="text-[8px] uppercase tracking-[0.2em] text-stone-300 font-bold">
              Archival philology
            </span>
          </div>
        </div>

        <nav className="flex items-center gap-10 text-[10px] uppercase tracking-[0.3em] font-black text-stone-400">
          <button 
            onClick={() => changeMode(AppMode.DICTIONARY)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.DICTIONARY ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Encyclopedia
          </button>
          <button 
            onClick={() => changeMode(AppMode.ARENA)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARENA ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            The Arena
          </button>
          <button 
            onClick={() => changeMode(AppMode.ARCHIVE)} 
            className={`hover:text-[#7c1a1a] transition-all border-b-2 py-1 ${mode === AppMode.ARCHIVE ? 'border-[#7c1a1a] text-stone-900' : 'border-transparent'}`}
          >
            Chronicles
          </button>
        </nav>
      </header>

      <main className="flex-1">
        <div className="max-w-[1400px] mx-auto px-6 md:px-12 pb-20">
          {mode === AppMode.DICTIONARY && (
            <Dictionary 
              onEntrySaved={addEntry} 
              autoAudio={autoAudio} 
              setAutoAudio={setAutoAudio}
              profile={profile}
              history={history}
              onStartArena={() => changeMode(AppMode.ARENA)}
              selectedEntry={activeEntry}
              onEntryClick={(e) => { triggerHaptic('light'); setActiveEntry(e); }}
              triggerHaptic={triggerHaptic}
            />
          )}

          {mode === AppMode.ARENA && (
            <Arena history={history} onResult={handleArenaResult} />
          )}

          {mode === AppMode.ARCHIVE && (
            <Archive history={history} onEntryClick={(e) => { triggerHaptic('light'); setActiveEntry(e); setMode(AppMode.DICTIONARY); }} />
          )}
        </div>
      </main>

      <footer className="py-12 border-t border-stone-100 bg-white/50">
        <div className="max-w-[1400px] mx-auto px-12 flex flex-col md:flex-row justify-between items-center gap-6 text-[10px] uppercase tracking-[0.3em] text-stone-400 font-black">
          <div className="flex items-center gap-4">
             <span>&copy; 2025 LEXICON PHILOLOGY</span>
             <span className="text-stone-200">/</span>
             <span className={`flex items-center gap-1.5 ${syncStatus === 'synced' ? 'text-green-600' : syncStatus === 'syncing' ? 'text-amber-500' : 'text-red-500'}`}>
                <span className={`w-1.5 h-1.5 rounded-full ${syncStatus === 'synced' ? 'bg-green-500' : syncStatus === 'syncing' ? 'bg-amber-500 animate-pulse' : 'bg-red-500'}`}></span>
                {tg ? 'TELEGRAM CLOUD' : 'LOCAL CACHE'} {syncStatus.toUpperCase()}
             </span>
          </div>
          <div className="flex items-center gap-8">
            <span className="flex items-center gap-2">
              <span className="w-2 h-2 rounded-full bg-[#7c1a1a] animate-pulse"></span>
              {profile.rank}
            </span>
            <span className="text-stone-900">LVL {Math.floor(profile.xp / 1000) + 1}</span>
            <span className="text-stone-300">{profile.accuracy}% ACCURACY</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWord } from '../services/gemini';
import { speak } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
  triggerHaptic?: (type?: any) => void;
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS'
};

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Russian') {
    res = res.replace(/ё/g, 'е');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  onStartArena, 
  selectedEntry,
  onEntryClick,
  triggerHaptic
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>('German');
  const [targetLang, setTargetLang] = useState<Language>('Uzbek');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<LexicalEntry | null>(null);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  const handleSourceLangChange = (lang: Language) => {
    if (lang === sourceLang) return;
    triggerHaptic?.('light');
    if (lang === targetLang) setTargetLang(sourceLang);
    setSourceLang(lang);
  };

  const handleTargetLangChange = (lang: Language) => {
    if (lang === targetLang) return;
    triggerHaptic?.('light');
    if (lang === sourceLang) setSourceLang(targetLang);
    setTargetLang(lang);
  };

  const unifiedCache = useMemo(() => {
    const cache = new Map<string, LexicalEntry>();

    Object.entries(SEED_ARCHIVE).forEach(([key, entry]) => {
      const parts = key.split('-');
      const sL = parts[1] as Language;
      const tL = parts[2] as Language;
      const norm = normalize(entry.term!, sL);
      cache.set(`${norm}-${sL}-${tL}`, { 
        ...entry, 
        id: `seed-${key}`, 
        normalizedTerm: norm,
        sourceLang: sL,
        targetLang: tL
      } as any);
    });

    history.forEach(entry => {
      const norm = normalize(entry.term, entry.sourceLang);
      cache.set(`${norm}-${entry.sourceLang}-${entry.targetLang}`, entry);
    });

    return cache;
  }, [history]);

  const handleSearch = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!query.trim()) return;

    triggerHaptic?.('medium');
    if (autoAudio) speak(query, sourceLang);

    const normQuery = normalize(query, sourceLang);
    const cacheKey = `${normQuery}-${sourceLang}-${targetLang}`;
    const fastHit = unifiedCache.get(cacheKey);

    if (fastHit) {
      setResult(fastHit);
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      const finalEntry = await translateWord(query, sourceLang, targetLang);
      finalEntry.normalizedTerm = normQuery;
      setResult(finalEntry);
      onEntrySaved(finalEntry);
    } catch (err) {
      console.error("Philologist Engine Error:", err);
    } finally {
      setLoading(false);
    }
  };

  const swapLanguages = () => {
    triggerHaptic?.('medium');
    const prevSource = sourceLang;
    setSourceLang(targetLang);
    setTargetLang(prevSource);
  };

  return (
    <div className="space-y-8 md:space-y-12 max-w-7xl mx-auto">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6 pt-4">
        <div className="space-y-2 border-l-[3px] border-[#7c1a1a] pl-6 hidden sm:block">
          <span className="text-[10px] uppercase tracking-[0.4em] text-stone-400 font-black">Philological Mastery</span>
          <div className="flex items-baseline gap-3">
            <span className="text-4xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
            <span className="text-[10px] uppercase tracking-widest text-stone-300 font-bold">Total XP Earned</span>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-3 bg-stone-50 p-2 rounded-sm w-full sm:w-auto border border-stone-100">
             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full}
                    type="button"
                    onClick={() => handleSourceLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-300 hover:text-stone-600'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>

             <button 
                type="button" 
                onClick={swapLanguages}
                className="text-stone-300 hover:text-[#7c1a1a] p-2 transition-all hover:bg-white rounded-full"
                title="Swap Languages"
             >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M7 16V4M7 4L3 8M7 4L11 8M17 8v12M17 20l4-4M17 20l-4-4"/></svg>
             </button>

             <div className="grid grid-cols-4 bg-white shadow-sm overflow-hidden rounded-sm w-full sm:w-auto">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button 
                    key={full}
                    type="button"
                    onClick={() => handleTargetLangChange(full)}
                    className={`px-2 sm:px-4 py-2.5 text-[9px] sm:text-[10px] font-black tracking-widest border-r border-stone-100 last:border-r-0 transition-all ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-300 hover:text-stone-600'}`}
                  >
                    {short}
                  </button>
                ))}
             </div>
          </div>

          <div className="flex items-center gap-6">
            <button 
              onClick={() => setAutoAudio(!autoAudio)}
              className={`flex items-center gap-2 text-[10px] font-black tracking-widest uppercase transition-all ${autoAudio ? 'text-[#7c1a1a]' : 'text-stone-300'}`}
            >
              <span className={`w-2 h-2 rounded-full ${autoAudio ? 'bg-[#7c1a1a] animate-pulse' : 'bg-stone-200'}`}></span>
              Auto-Audio
            </button>
          </div>
        </div>
      </div>

      <div className="relative group max-w-4xl mx-auto w-full">
        <form onSubmit={handleSearch}>
          <input 
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search the lexicon..."
            className="w-full bg-white border-b-2 border-stone-100 p-8 md:p-12 text-3xl md:text-6xl serif font-black tracking-tighter placeholder:text-stone-100 focus:outline-none focus:border-[#7c1a1a] transition-all lowercase"
          />
          <button 
            type="submit"
            disabled={loading || !query.trim()}
            className="absolute right-4 bottom-8 md:bottom-12 p-4 text-stone-200 hover:text-[#7c1a1a] disabled:opacity-0 transition-all"
          >
            {loading ? (
              <div className="w-8 h-8 border-4 border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
            ) : (
              <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
            )}
          </button>
        </form>
      </div>

      {result && <ResultCard entry={result} />}

      {!result && !loading && history.length > 0 && (
        <section className="pt-12">
          <div className="flex justify-between items-end mb-8 border-b border-stone-100 pb-4">
            <h2 className="text-[11px] uppercase tracking-[0.4em] font-black text-stone-900">Recent Inscriptions</h2>
            <button 
              onClick={onStartArena}
              className="text-[10px] font-black uppercase tracking-widest text-[#7c1a1a] hover:underline"
            >
              Test Knowledge in Arena →
